//! NetX Duo BSD socket networking for ThreadX.
//!
//! Implements PlatformTcp, PlatformUdp, PlatformSocketHelpers on
//! ThreadxPlatform using NetX Duo's BSD socket API (`nx_bsd_*`).
//!
//! Types and constants are auto-generated by `threadx-netx-sys` (bindgen),
//! eliminating manual constant mismatches (SOL_SOCKET, SO_RCVTIMEO, etc.).

#![allow(unsafe_op_in_unsafe_fn)]

use core::ffi::{c_int, c_void};

use crate::ThreadxPlatform;
use threadx_netx_sys::*;

// ============================================================================
// C struct wrappers matching zenoh-pico's ThreadX platform types
// ============================================================================

/// Socket: `{ int _fd; }` (matches _z_sys_net_socket_t)
#[repr(C)]
struct Socket {
    _fd: c_int,
}

/// Endpoint: `{ uint32_t _addr; uint16_t _port; }` (matches _z_sys_net_endpoint_t)
#[repr(C)]
#[derive(Clone, Copy)]
struct Endpoint {
    _addr: u32, // IPv4 in host byte order
    _port: u16, // port in host byte order
}

// ============================================================================
// Helpers
// ============================================================================

/// Parse "a.b.c.d" → host-byte-order u32.
fn parse_ipv4(s: *const u8) -> u32 {
    if s.is_null() {
        return 0;
    }
    let mut octets = [0u32; 4];
    let mut idx = 0usize;
    let mut val: u32 = 0;
    let mut has_digit = false;
    let mut p = s;

    loop {
        let ch = unsafe { *p };
        if ch == 0 {
            break;
        }
        if ch.is_ascii_digit() {
            val = val * 10 + (ch - b'0') as u32;
            has_digit = true;
        } else if ch == b'.' {
            if !has_digit || idx >= 3 {
                return 0;
            }
            octets[idx] = val;
            idx += 1;
            val = 0;
            has_digit = false;
        } else {
            return 0;
        }
        p = unsafe { p.add(1) };
    }

    if !has_digit || idx != 3 {
        return 0;
    }
    octets[3] = val;

    (octets[0] << 24) | (octets[1] << 16) | (octets[2] << 8) | octets[3]
}

fn parse_port(s: *const u8) -> u16 {
    if s.is_null() {
        return 0;
    }
    let mut val: u32 = 0;
    let mut p = s;
    loop {
        let ch = unsafe { *p };
        if ch == 0 {
            break;
        }
        if ch.is_ascii_digit() {
            val = val * 10 + (ch - b'0') as u32;
        } else {
            return 0;
        }
        p = unsafe { p.add(1) };
    }
    val as u16
}

fn ep_to_sockaddr(ep: &Endpoint) -> nx_bsd_sockaddr_in {
    nx_bsd_sockaddr_in {
        sin_family: AF_INET as _,
        sin_port: htons(ep._port),
        sin_addr: nx_bsd_in_addr {
            s_addr: htonl(ep._addr),
        },
        sin_zero: [0; 8],
    }
}

// ============================================================================
// TCP
// ============================================================================

impl ThreadxPlatform {
    pub fn tcp_create_endpoint(ep: *mut c_void, address: *const u8, port: *const u8) -> i8 {
        let ep = ep as *mut Endpoint;
        let addr = parse_ipv4(address);
        let p = parse_port(port);
        if addr == 0 {
            return -1;
        }
        unsafe {
            (*ep)._addr = addr;
            (*ep)._port = p;
        }
        0
    }

    pub fn tcp_free_endpoint(_ep: *mut c_void) {}

    pub fn tcp_open(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        let fd = unsafe { nx_bsd_socket(AF_INET as INT, SOCK_STREAM as INT, IPPROTO_TCP as INT) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._fd = fd };

        // SO_RCVTIMEO (NetX BSD takes INT milliseconds, not struct timeval)
        if timeout_ms > 0 {
            let tv_ms: INT = timeout_ms as INT;
            unsafe {
                nx_bsd_setsockopt(
                    fd,
                    SOL_SOCKET as INT,
                    SO_RCVTIMEO as INT,
                    &tv_ms as *const _ as *const c_void,
                    core::mem::size_of::<INT>() as INT,
                );
            }
        }

        let addr = ep_to_sockaddr(rep);
        let rc = unsafe {
            nx_bsd_connect(
                fd,
                &addr as *const nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                core::mem::size_of::<nx_bsd_sockaddr_in>() as INT,
            )
        };
        if rc < 0 {
            unsafe {
                nx_bsd_soc_close(fd);
                (*sock)._fd = -1;
            }
            return -1;
        }

        0
    }

    pub fn tcp_listen(sock: *mut c_void, endpoint: *const c_void) -> i8 {
        let sock = sock as *mut Socket;
        let lep = unsafe { &*(endpoint as *const Endpoint) };

        let fd = unsafe { nx_bsd_socket(AF_INET as INT, SOCK_STREAM as INT, IPPROTO_TCP as INT) };
        if fd < 0 {
            return -1;
        }

        let one: INT = 1;
        unsafe {
            nx_bsd_setsockopt(
                fd,
                SOL_SOCKET as INT,
                SO_REUSEADDR as INT,
                &one as *const _ as *const c_void,
                core::mem::size_of::<INT>() as INT,
            );
        }

        let addr = ep_to_sockaddr(lep);
        if unsafe {
            nx_bsd_bind(
                fd,
                &addr as *const nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                core::mem::size_of::<nx_bsd_sockaddr_in>() as INT,
            )
        } < 0
        {
            unsafe { nx_bsd_soc_close(fd) };
            return -1;
        }

        if unsafe { nx_bsd_listen(fd, 1) } < 0 {
            unsafe { nx_bsd_soc_close(fd) };
            return -1;
        }

        unsafe { (*sock)._fd = fd };
        0
    }

    pub fn tcp_close(sock: *mut c_void) {
        let sock = sock as *mut Socket;
        let fd = unsafe { (*sock)._fd };
        if fd >= 0 {
            unsafe {
                nx_bsd_soc_close(fd);
                (*sock)._fd = -1;
            }
        }
    }

    pub fn tcp_read(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._fd < 0 {
            return usize::MAX;
        }
        let n = unsafe { nx_bsd_recv(sock._fd, buf as *mut _ as *mut _, len as INT, 0) };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn tcp_read_exact(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._fd < 0 {
            return usize::MAX;
        }
        let mut total: usize = 0;
        while total < len {
            let n = unsafe {
                nx_bsd_recv(
                    sock._fd,
                    buf.add(total) as *mut _ as *mut _,
                    (len - total) as INT,
                    0,
                )
            };
            if n <= 0 {
                return usize::MAX;
            }
            total += n as usize;
        }
        total
    }

    pub fn tcp_send(sock: *const c_void, buf: *const u8, len: usize) -> usize {
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._fd < 0 {
            return usize::MAX;
        }
        let mut total: usize = 0;
        while total < len {
            let n = unsafe {
                nx_bsd_send(
                    sock._fd,
                    buf.add(total) as *const CHAR,
                    (len - total) as INT,
                    0,
                )
            };
            if n <= 0 {
                return usize::MAX;
            }
            total += n as usize;
        }
        total
    }
}

// ============================================================================
// UDP
// ============================================================================

impl ThreadxPlatform {
    pub fn udp_create_endpoint(ep: *mut c_void, address: *const u8, port: *const u8) -> i8 {
        Self::tcp_create_endpoint(ep, address, port)
    }

    pub fn udp_free_endpoint(_ep: *mut c_void) {}

    pub fn udp_open(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        let fd = unsafe { nx_bsd_socket(AF_INET as INT, SOCK_DGRAM as INT, IPPROTO_UDP as INT) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._fd = fd };

        if timeout_ms > 0 {
            let tv_ms: INT = timeout_ms as INT;
            unsafe {
                nx_bsd_setsockopt(
                    fd,
                    SOL_SOCKET as INT,
                    SO_RCVTIMEO as INT,
                    &tv_ms as *const _ as *const c_void,
                    core::mem::size_of::<INT>() as INT,
                );
            }
        }

        // Connect for send/recv
        let addr = ep_to_sockaddr(rep);
        if unsafe {
            nx_bsd_connect(
                fd,
                &addr as *const nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                core::mem::size_of::<nx_bsd_sockaddr_in>() as INT,
            )
        } < 0
        {
            unsafe {
                nx_bsd_soc_close(fd);
                (*sock)._fd = -1;
            }
            return -1;
        }

        0
    }

    /// Phase 71.21 — bind a UDP socket for inbound use via NetX BSD.
    pub fn udp_listen(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        let fd = unsafe { nx_bsd_socket(AF_INET as INT, SOCK_DGRAM as INT, IPPROTO_UDP as INT) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._fd = fd };

        let one: INT = 1;
        unsafe {
            nx_bsd_setsockopt(
                fd,
                SOL_SOCKET as INT,
                SO_REUSEADDR as INT,
                &one as *const _ as *const c_void,
                core::mem::size_of::<INT>() as INT,
            );
        }

        if timeout_ms > 0 {
            let tv_ms: INT = timeout_ms as INT;
            unsafe {
                nx_bsd_setsockopt(
                    fd,
                    SOL_SOCKET as INT,
                    SO_RCVTIMEO as INT,
                    &tv_ms as *const _ as *const c_void,
                    core::mem::size_of::<INT>() as INT,
                );
            }
        }

        let addr = ep_to_sockaddr(rep);
        if unsafe {
            nx_bsd_bind(
                fd,
                &addr as *const nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                core::mem::size_of::<nx_bsd_sockaddr_in>() as INT,
            )
        } < 0
        {
            unsafe {
                nx_bsd_soc_close(fd);
                (*sock)._fd = -1;
            }
            return -1;
        }
        0
    }

    pub fn udp_close(sock: *mut c_void) {
        Self::tcp_close(sock);
    }

    pub fn udp_read(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._fd < 0 {
            return usize::MAX;
        }
        let n = unsafe { nx_bsd_recv(sock._fd, buf as *mut _ as *mut _, len as INT, 0) };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn udp_read_exact(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        Self::udp_read(sock, buf, len)
    }

    pub fn udp_send(
        sock: *const c_void,
        buf: *const u8,
        len: usize,
        endpoint: *const c_void,
    ) -> usize {
        let sock = unsafe { &*(sock as *const Socket) };
        let rep = unsafe { &*(endpoint as *const Endpoint) };
        if sock._fd < 0 {
            return usize::MAX;
        }
        let addr = ep_to_sockaddr(rep);
        let n = unsafe {
            nx_bsd_sendto(
                sock._fd,
                buf as *const _ as *mut _,
                len as INT,
                0,
                &addr as *const nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                core::mem::size_of::<nx_bsd_sockaddr_in>() as INT,
            )
        };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn udp_set_recv_timeout(sock: *const c_void, timeout_ms: u32) {
        let sock = unsafe { &*(sock as *const Socket) };
        // NetX BSD takes INT milliseconds, not struct timeval
        let tv_ms: INT = timeout_ms as INT;
        unsafe {
            nx_bsd_setsockopt(
                sock._fd,
                SOL_SOCKET as INT,
                SO_RCVTIMEO as INT,
                &tv_ms as *const _ as *const c_void,
                core::mem::size_of::<INT>() as INT,
            );
        }
    }
}

// ============================================================================
// Socket helpers
// ============================================================================

impl ThreadxPlatform {
    pub fn socket_set_non_blocking(_sock: *const c_void) -> i8 {
        0 // NetX Duo BSD does not support fcntl/O_NONBLOCK
    }

    pub fn socket_accept(sock_in: *const c_void, sock_out: *mut c_void) -> i8 {
        let sin = unsafe { &*(sock_in as *const Socket) };
        let sout = sock_out as *mut Socket;
        let mut addr: nx_bsd_sockaddr_in = unsafe { core::mem::zeroed() };
        let mut addrlen: INT = core::mem::size_of::<nx_bsd_sockaddr_in>() as INT;

        let fd = unsafe {
            nx_bsd_accept(
                sin._fd,
                &mut addr as *mut nx_bsd_sockaddr_in as *mut nx_bsd_sockaddr,
                &mut addrlen,
            )
        };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sout)._fd = fd };
        0
    }

    pub fn socket_close(sock: *mut c_void) {
        Self::tcp_close(sock);
    }

    pub fn socket_wait_event(_peers: *mut c_void, _mutex: *mut c_void) -> i8 {
        // Phase 77.22: delegate to `PlatformYield::yield_now()`
        // (`tx_thread_relinquish` instead of `tx_thread_sleep(1)`).
        use nros_platform_api::PlatformYield;
        <Self as PlatformYield>::yield_now();
        0
    }
}

